 *     bytes32 internal constant _IMPLEMENTATION_SLOT = 0x360894a13ba1a3210667c828492db98dca3e2076cc3735a920a3ca505d382bbc;
 *
 *     function _getImplementation() internal view returns (address) {
 *         return StorageSlot.getAddressSlot(_IMPLEMENTATION_SLOT).value;
 *     }
 *
 *     function _setImplementation(address newImplementation) internal {
 *         require(newImplementation.code.length > 0);
 *         StorageSlot.getAddressSlot(_IMPLEMENTATION_SLOT).value = newImplementation;
 *     }
 * }
 * ```
 *
 * TIP: Consider using this library along with {SlotDerivation}.
 */
library StorageSlot {
    struct AddressSlot {
        address value;
    }

    struct BooleanSlot {
        bool value;
    }

    struct Bytes32Slot {
        bytes32 value;
    }

    struct Uint256Slot {
        uint256 value;
    }

    struct Int256Slot {
        int256 value;
    }

    struct StringSlot {
        string value;
    }

    struct BytesSlot {
        bytes value;
    }

    /**
     * @dev Returns an `AddressSlot` with member `value` located at `slot`.
     */
    function getAddressSlot(bytes32 slot) internal pure returns (AddressSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `BooleanSlot` with member `value` located at `slot`.
     */
    function getBooleanSlot(bytes32 slot) internal pure returns (BooleanSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Bytes32Slot` with member `value` located at `slot`.
     */
    function getBytes32Slot(bytes32 slot) internal pure returns (Bytes32Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Uint256Slot` with member `value` located at `slot`.
     */
    function getUint256Slot(bytes32 slot) internal pure returns (Uint256Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Int256Slot` with member `value` located at `slot`.
     */
    function getInt256Slot(bytes32 slot) internal pure returns (Int256Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `StringSlot` with member `value` located at `slot`.
     */
    function getStringSlot(bytes32 slot) internal pure returns (StringSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns an `StringSlot` representation of the string storage pointer `store`.
     */
    function getStringSlot(string storage store) internal pure returns (StringSlot storage r) {
        assembly ("memory-safe") {
            r.slot := store.slot
        }
    }

    /**
     * @dev Returns a `BytesSlot` with member `value` located at `slot`.
     */
    function getBytesSlot(bytes32 slot) internal pure returns (BytesSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns an `BytesSlot` representation of the bytes storage pointer `store`.
     */
    function getBytesSlot(bytes storage store) internal pure returns (BytesSlot storage r) {
        assembly ("memory-safe") {
            r.slot := store.slot
        }
    }
}

contracts/FatDeflationary.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./interfaces/IUniswapV2Router02.sol";

/**
 * @title FatDeflationary
 * @dev ERC-20 deflationary token — same battle-tested tax architecture as FatTax,
 *      with a permanent burn component. Every `deflationPercent` slice of collected tax
 *      is burned via ERC20 `_burn`, permanently reducing `totalSupply`.
 *
 * Features:
 * - Separate tax rates for Transfers, Buys, and Sells
 * - Flexible tax distribution: marketing, liquidity, team, buyback, BURN (deflationary)
 * - AUTO-SWAP: Tax tokens automatically swapped to ETH via DEX Router
 * - AUTO-LIQUIDITY: Liquidity portion auto-added to DEX (LP tokens to owner)
 * - DEX pair management for buy/sell detection
 * - Comprehensive exemption system
 * - `totalBurned()` view tracks cumulative supply destroyed
 */
contract FatDeflationary is ERC20, Ownable, ReentrancyGuard {

    // ============================================
    // STRUCTS
    // ============================================

    struct TaxBehavior {
        bool taxOnTransfer;     // Apply tax on wallet-to-wallet transfers
        bool taxOnBuy;          // Apply tax when buying from DEX
        bool taxOnSell;         // Apply tax when selling to DEX
        uint256 transferTax;    // Tax rate for transfers (basis points, e.g., 200 = 2%)
        uint256 buyTax;         // Tax rate for buys (basis points)
        uint256 sellTax;        // Tax rate for sells (basis points)
    }

    struct TaxDistribution {
        uint256 marketingPercent;   // % of tax to marketing (0-10000) → ETH
        uint256 liquidityPercent;   // % of tax to auto-liquidity (0-10000) → Auto-add to DEX
        uint256 teamPercent;        // % of tax to team (0-10000) → ETH
        uint256 buybackPercent;     // % of tax to buyback (0-10000) → ETH
        uint256 deflationPercent;   // % of tax to burn (0-10000) → Burned as tokens
        // These MUST add up to 10000 (100% of collected tax)

        address marketingWallet;    // Receives ETH (address(0) if not used)
        address teamWallet;         // Receives ETH (address(0) if not used)
        address buybackWallet;      // Receives ETH (address(0) if not used)
    }

    // ============================================
    // STATE VARIABLES
    // ============================================

    string private _tokenName;
    string private _tokenSymbol;
    uint8 private _decimals;

    TaxBehavior public taxBehavior;
    TaxDistribution public taxDistribution;

    mapping(address => bool) public isExempt;
    mapping(address => bool) public isDexPair;

    address[] private _dexPairs;

    IUniswapV2Router02 public dexRouter;
    uint256 public swapTokensAtAmount;
    bool private _inSwap;
    bool public autoSwapEnabled;

    bool private _initialized;

    uint256 public slippageTolerance = 500;
    uint256 public swapDeadline = 300;

    uint256 public constant MAX_TAX = 2500;
    uint256 public constant MAX_SLIPPAGE = 1000;
    uint256 public constant BASIS_POINTS = 10000;
    uint256 public constant MAX_SWAP_MULTIPLIER = 20;
    address public constant DEAD_ADDRESS = 0x000000000000000000000000000000000000dEaD;

    uint256 private _totalBurned;

    // ============================================
    // EVENTS
    // ============================================

    event TaxCollected(address indexed from, string transferType, uint256 totalTax, uint256 tokensToContract);
    event SwapAndDistribute(uint256 tokensSwapped, uint256 ethReceived, uint256 ethToMarketing, uint256 ethToTeam, uint256 ethToBuyback);
    event LiquidityAdded(uint256 tokensAdded, uint256 ethAdded, uint256 liquidity);
    event ExemptStatusChanged(address indexed account, bool status);
    event DexPairUpdated(address indexed pair, bool status);
    event TaxBehaviorUpdated(TaxBehavior newBehavior);
    event TaxDistributionUpdated(TaxDistribution newDistribution);
    event RouterUpdated(address indexed newRouter);
    event SwapThresholdUpdated(uint256 newThreshold);
    event AutoSwapEnabledUpdated(bool enabled);
    event SlippageToleranceUpdated(uint256 newTolerance);
    event SwapDeadlineUpdated(uint256 newDeadline);
    event DistributionFailed(string wallet, uint256 amount);
    event ETHRecovered(uint256 amount);
    event ERC20Recovered(address indexed token, uint256 amount);
    event MEVProtectionUpdated(bool enabled);
    event Deflated(uint256 amount, uint256 totalBurnedAfter);
    event TransferFailed(address indexed from, address indexed to, uint256 amount, string reason);
    event OwnershipRenounced(address indexed previousOwner, uint256 timestamp);

    // ============================================
    // ERRORS
    // ============================================

    error AlreadyInitialized();
    error TaxTooHigh(uint256 provided, uint256 max);
    error InvalidTaxWallet(string walletType);
    error InvalidDistribution(uint256 total, uint256 expected);

    // ============================================
    // CONSTRUCTOR
    // ============================================

    constructor() ERC20("Implementation", "IMPL") Ownable(msg.sender) {
        // (removed: was clone guard)
    }

    // ============================================
    // INITIALIZATION
    // ============================================

    function initialize(
        string memory name_,
        string memory symbol_,
        uint8 decimals_,
        uint256 totalSupply_,
        address owner_,
        TaxBehavior memory taxBehavior_,
        TaxDistribution memory taxDistribution_,
        address dexRouter_
    ) external {
        if (_initialized) revert AlreadyInitialized();

        if (taxBehavior_.transferTax > MAX_TAX) revert TaxTooHigh(taxBehavior_.transferTax, MAX_TAX);
        if (taxBehavior_.buyTax > MAX_TAX) revert TaxTooHigh(taxBehavior_.buyTax, MAX_TAX);
        if (taxBehavior_.sellTax > MAX_TAX) revert TaxTooHigh(taxBehavior_.sellTax, MAX_TAX);

        uint256 totalDistribution = taxDistribution_.marketingPercent +
                                     taxDistribution_.liquidityPercent +
                                     taxDistribution_.teamPercent +
                                     taxDistribution_.buybackPercent +
                                     taxDistribution_.deflationPercent;

        if (totalDistribution != BASIS_POINTS) {
            revert InvalidDistribution(totalDistribution, BASIS_POINTS);
        }

        if (taxDistribution_.marketingPercent > 0 && taxDistribution_.marketingWallet == address(0)) {
            revert InvalidTaxWallet("marketing");
        }
        if (taxDistribution_.teamPercent > 0 && taxDistribution_.teamWallet == address(0)) {
            revert InvalidTaxWallet("team");
        }
        if (taxDistribution_.buybackPercent > 0 && taxDistribution_.buybackWallet == address(0)) {
            revert InvalidTaxWallet("buyback");
        }

        _setName(name_);
        _setSymbol(symbol_);

        _decimals = decimals_;
        taxBehavior = taxBehavior_;
        taxDistribution = taxDistribution_;

        dexRouter = IUniswapV2Router02(dexRouter_);
        swapTokensAtAmount = totalSupply_ / 20000;
        autoSwapEnabled = true;

        slippageTolerance = 500;
        swapDeadline = 300;

        _transferOwnership(owner_);

        if (totalSupply_ > 0) {
            _mint(owner_, totalSupply_);
        }

        isExempt[owner_] = true;
        isExempt[address(this)] = true;
        if (taxDistribution_.marketingWallet != address(0)) isExempt[taxDistribution_.marketingWallet] = true;
        if (taxDistribution_.teamWallet != address(0)) isExempt[taxDistribution_.teamWallet] = true;
        if (taxDistribution_.buybackWallet != address(0)) isExempt[taxDistribution_.buybackWallet] = true;
        isExempt[DEAD_ADDRESS] = true;

        _initialized = true;
    }

    // ============================================
    // INTERNAL STORAGE SETTERS
    // ============================================

    function name() public view override returns (string memory) { return _tokenName; }
    function symbol() public view override returns (string memory) { return _tokenSymbol; }
    function _setName(string memory name_) private { _tokenName = name_; }
    function _setSymbol(string memory symbol_) private { _tokenSymbol = symbol_; }

    // ============================================
    // ERC20 OVERRIDES
    // ============================================

    function decimals() public view virtual override returns (uint8) {
        return _decimals;
    }

    function _update(address from, address to, uint256 amount) internal virtual override(ERC20) {
        if (from == address(0) || to == address(0)) {
            super._update(from, to, amount);
            return;
        }

        if (isExempt[from] || isExempt[to]) {
            super._update(from, to, amount);
            return;
        }

        (bool shouldTax, uint256 taxRate, string memory transferType) = _getTaxInfo(from, to);

        uint256 taxAmount = 0;
        uint256 amountAfterTax = amount;

        if (shouldTax && taxRate > 0) {
            taxAmount = (amount * taxRate) / BASIS_POINTS;
            amountAfterTax = amount - taxAmount;
        }

        if (taxAmount > 0) {
            _distributeTax(from, taxAmount, transferType);
        }

        super._update(from, to, amountAfterTax);
    }

    // ============================================
    // TAX LOGIC
    // ============================================

    function _getTaxInfo(address from, address to)
        private view
        returns (bool shouldTax, uint256 taxRate, string memory transferType)
    {
        bool isBuy = isDexPair[from] && !isDexPair[to];
        bool isSell = !isDexPair[from] && isDexPair[to];
        bool isTransfer = !isDexPair[from] && !isDexPair[to];

        if (isBuy) {
            transferType = "BUY"; shouldTax = taxBehavior.taxOnBuy; taxRate = taxBehavior.buyTax;
        } else if (isSell) {
            transferType = "SELL"; shouldTax = taxBehavior.taxOnSell; taxRate = taxBehavior.sellTax;
        } else if (isTransfer) {
            transferType = "TRANSFER"; shouldTax = taxBehavior.taxOnTransfer; taxRate = taxBehavior.transferTax;
        } else {
            transferType = "DEX_TO_DEX"; shouldTax = false; taxRate = 0;
        }
    }

    function _distributeTax(address from, uint256 totalTax, string memory transferType) private {
        super._update(from, address(this), totalTax);
        emit TaxCollected(from, transferType, totalTax, totalTax);

        if (autoSwapEnabled) {
            uint256 contractBalance = balanceOf(address(this));
            bool canSwap = contractBalance >= swapTokensAtAmount;

            if (canSwap && !_inSwap && !isDexPair[from]) {
                uint256 maxSwap = swapTokensAtAmount * MAX_SWAP_MULTIPLIER;
                uint256 swapAmount = contractBalance > maxSwap ? maxSwap : contractBalance;
                try this.autoSwapEntry(swapAmount) {} catch {}
            }
        }
    }

    function autoSwapEntry(uint256 amount) external {
        require(msg.sender == address(this), "Only self");
        _swapAndDistribute(amount);
    }

    // ============================================
    // SWAP & LIQUIDITY FUNCTIONS
    // ============================================

    modifier lockTheSwap {
        _inSwap = true;
        _;
        _inSwap = false;
    }

    function _swapTokensForEth(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = dexRouter.WETH();
        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount, 0, path, address(this), block.timestamp + swapDeadline
        );
    }

    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        address lpRecipient = owner();
        if (lpRecipient == address(0)) lpRecipient = 0x000000000000000000000000000000000000dEaD;
        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.addLiquidityETH{value: ethAmount}(address(this), tokenAmount, 0, 0, lpRecipient, block.timestamp + swapDeadline);
        emit LiquidityAdded(tokenAmount, ethAmount, 0);
    }

    function _swapAndDistribute(uint256 taxAmount) private lockTheSwap {
        uint256 burnAmount = (taxAmount * taxDistribution.deflationPercent) / BASIS_POINTS;
        uint256 liquidityTokens = (taxAmount * taxDistribution.liquidityPercent) / BASIS_POINTS;
        uint256 swapTokens = taxAmount - burnAmount - liquidityTokens;

        if (burnAmount > 0) {
            super._update(address(this), DEAD_ADDRESS, burnAmount);
            emit Transfer(address(this), DEAD_ADDRESS, burnAmount);
            _totalBurned += burnAmount;
            emit Deflated(burnAmount, _totalBurned);
        }

        if (liquidityTokens > 0) {
            uint256 half = liquidityTokens / 2;
            uint256 otherHalf = liquidityTokens - half;
            uint256 initialBalance = address(this).balance;
            _swapTokensForEth(half);
            _addLiquidity(otherHalf, address(this).balance - initialBalance);
        }

        if (swapTokens > 0) {
            uint256 initialBalance = address(this).balance;
            _swapTokensForEth(swapTokens);
            uint256 ethForDistribution = address(this).balance - initialBalance;

            uint256 totalDistPercent = taxDistribution.marketingPercent + taxDistribution.teamPercent + taxDistribution.buybackPercent;
            uint256 ethToMarketing = 0; uint256 ethToTeam = 0; uint256 ethToBuyback = 0;

            if (totalDistPercent > 0) {
                ethToMarketing = (ethForDistribution * taxDistribution.marketingPercent) / totalDistPercent;
                ethToTeam = (ethForDistribution * taxDistribution.teamPercent) / totalDistPercent;
                ethToBuyback = ethForDistribution - ethToMarketing - ethToTeam;
            }

            if (ethToMarketing > 0) { (bool s,) = taxDistribution.marketingWallet.call{value: ethToMarketing}(""); if (!s) emit DistributionFailed("marketing", ethToMarketing); }
            if (ethToTeam > 0) { (bool s,) = taxDistribution.teamWallet.call{value: ethToTeam}(""); if (!s) emit DistributionFailed("team", ethToTeam); }
            if (ethToBuyback > 0) { (bool s,) = taxDistribution.buybackWallet.call{value: ethToBuyback}(""); if (!s) emit DistributionFailed("buyback", ethToBuyback); }

            emit SwapAndDistribute(swapTokens, ethForDistribution, ethToMarketing, ethToTeam, ethToBuyback);
        }
    }

    receive() external payable {}

    function recoverETH() external onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        require(balance > 0, "No ETH to recover");
        (bool success,) = owner().call{value: balance}("");
        require(success, "ETH recovery failed");
        emit ETHRecovered(balance);
    }

    function recoverERC20(address tokenAddress, uint256 amount) external onlyOwner {
        require(tokenAddress != address(this), "Cannot recover own tokens");
        require(amount > 0, "Amount must be > 0");
        IERC20(tokenAddress).transfer(owner(), amount);
        emit ERC20Recovered(tokenAddress, amount);
    }

    function manualSwap() external onlyOwner nonReentrant {
        uint256 contractBalance = balanceOf(address(this));
        require(contractBalance > 0, "No tokens to swap");
        _swapAndDistribute(contractBalance);
    }

    function manualSwapAmount(uint256 amount) external onlyOwner nonReentrant {
        uint256 contractBalance = balanceOf(address(this));
        require(amount > 0 && amount <= contractBalance, "Invalid amount");
        _swapAndDistribute(amount);
    }

    // ============================================
    // OWNER FUNCTIONS
    // ============================================

    function setExempt(address account, bool status) external onlyOwner { isExempt[account] = status; emit ExemptStatusChanged(account, status); }

    function setExemptBatch(address[] calldata accounts, bool status) external onlyOwner {
        for (uint256 i = 0; i < accounts.length; i++) { isExempt[accounts[i]] = status; emit ExemptStatusChanged(accounts[i], status); }
    }

    function setDexPair(address pair, bool status) public onlyOwner {
        if (status && !isDexPair[pair]) { _dexPairs.push(pair); }
        else if (!status && isDexPair[pair]) {
            for (uint256 i = 0; i < _dexPairs.length; i++) {
                if (_dexPairs[i] == pair) { _dexPairs[i] = _dexPairs[_dexPairs.length - 1]; _dexPairs.pop(); break; }
            }
        }
        isDexPair[pair] = status;
        emit DexPairUpdated(pair, status);
    }

    function setDexPairBatch(address[] calldata pairs, bool status) external onlyOwner {
        for (uint256 i = 0; i < pairs.length; i++) { setDexPair(pairs[i], status); }
    }

    function updateTaxBehavior(TaxBehavior memory newBehavior) external onlyOwner {
        if (newBehavior.transferTax > MAX_TAX) revert TaxTooHigh(newBehavior.transferTax, MAX_TAX);
        if (newBehavior.buyTax > MAX_TAX) revert TaxTooHigh(newBehavior.buyTax, MAX_TAX);
        if (newBehavior.sellTax > MAX_TAX) revert TaxTooHigh(newBehavior.sellTax, MAX_TAX);
        taxBehavior = newBehavior;
        emit TaxBehaviorUpdated(newBehavior);
    }

    function updateTaxDistribution(TaxDistribution memory newDistribution) external onlyOwner {
        uint256 totalDistribution = newDistribution.marketingPercent + newDistribution.liquidityPercent +
                                     newDistribution.teamPercent + newDistribution.buybackPercent + newDistribution.deflationPercent;
        if (totalDistribution != BASIS_POINTS) revert InvalidDistribution(totalDistribution, BASIS_POINTS);
        if (newDistribution.marketingPercent > 0 && newDistribution.marketingWallet == address(0)) revert InvalidTaxWallet("marketing");
        if (newDistribution.teamPercent > 0 && newDistribution.teamWallet == address(0)) revert InvalidTaxWallet("team");
        if (newDistribution.buybackPercent > 0 && newDistribution.buybackWallet == address(0)) revert InvalidTaxWallet("buyback");

        if (taxDistribution.marketingWallet != address(0)) isExempt[taxDistribution.marketingWallet] = false;
        if (taxDistribution.teamWallet != address(0)) isExempt[taxDistribution.teamWallet] = false;
        if (taxDistribution.buybackWallet != address(0)) isExempt[taxDistribution.buybackWallet] = false;

        taxDistribution = newDistribution;

        if (newDistribution.marketingWallet != address(0)) isExempt[newDistribution.marketingWallet] = true;
        if (newDistribution.teamWallet != address(0)) isExempt[newDistribution.teamWallet] = true;
        if (newDistribution.buybackWallet != address(0)) isExempt[newDistribution.buybackWallet] = true;

        emit TaxDistributionUpdated(newDistribution);
    }

    function setDexRouter(address newRouter) external onlyOwner { require(newRouter != address(0), "Invalid router"); dexRouter = IUniswapV2Router02(newRouter); emit RouterUpdated(newRouter); }
    function setSwapThreshold(uint256 newThreshold) external onlyOwner { require(newThreshold > 0, "Threshold must be > 0"); require(newThreshold <= totalSupply() / 50, "Threshold too high"); swapTokensAtAmount = newThreshold; emit SwapThresholdUpdated(newThreshold); }
    function setSlippageTolerance(uint256 newTolerance) external onlyOwner { require(newTolerance <= MAX_SLIPPAGE, "Slippage too high"); slippageTolerance = newTolerance; emit SlippageToleranceUpdated(newTolerance); }
    function setSwapDeadline(uint256 newDeadline) external onlyOwner { require(newDeadline >= 60 && newDeadline <= 3600, "Deadline must be 1-60 minutes"); swapDeadline = newDeadline; emit SwapDeadlineUpdated(newDeadline); }
    function setAutoSwapEnabled(bool enabled) external onlyOwner { autoSwapEnabled = enabled; emit AutoSwapEnabledUpdated(enabled); }

    // ============================================
    // VIEW FUNCTIONS
    // ============================================

    function isInitialized() external view returns (bool) { return _initialized; }
    function getTaxBehavior() external view returns (TaxBehavior memory) { return taxBehavior; }
    function getTaxDistribution() external view returns (TaxDistribution memory) { return taxDistribution; }

    function calculateTax(address from, address to, uint256 amount)
        external view returns (uint256 taxAmount, uint256 netAmount, string memory transferType)
    {
        if (from == address(0) || to == address(0)) return (0, amount, "MINT_OR_BURN");
        if (isExempt[from] || isExempt[to]) return (0, amount, "EXEMPT");
        (bool shouldTax, uint256 taxRate, string memory txType) = _getTaxInfo(from, to);
        if (!shouldTax || taxRate == 0) return (0, amount, txType);
        taxAmount = (amount * taxRate) / BASIS_POINTS;
        netAmount = amount - taxAmount;
        transferType = txType;
    }

    function previewTaxDistribution(address from, address to, uint256 amount)
        external view
        returns (uint256 toRecipient, uint256 toMarketing, uint256 toLiquidity, uint256 toTeam, uint256 toBuyback, uint256 toBurn)
    {
        (uint256 totalTax, uint256 afterTax,) = this.calculateTax(from, to, amount);
        toRecipient = afterTax;
        if (totalTax > 0) {
            toMarketing = (totalTax * taxDistribution.marketingPercent) / BASIS_POINTS;
            toLiquidity = (totalTax * taxDistribution.liquidityPercent) / BASIS_POINTS;
            toTeam = (totalTax * taxDistribution.teamPercent) / BASIS_POINTS;
            toBuyback = (totalTax * taxDistribution.buybackPercent) / BASIS_POINTS;
            toBurn = (totalTax * taxDistribution.deflationPercent) / BASIS_POINTS;
        }
    }

    function canTransfer(address from, address /*to*/, uint256 amount) external view returns (bool success, string memory reason) {
        if (balanceOf(from) < amount) return (false, "Insufficient balance");
        return (true, "");
    }

    function detectTransferType(address from, address to) external view returns (string memory transferType) {
        if (from == address(0)) return "MINT";
        if (to == address(0)) return "BURN";
        if (isDexPair[from] && !isDexPair[to]) return "BUY";
        if (!isDexPair[from] && isDexPair[to]) return "SELL";
        if (isDexPair[from] && isDexPair[to]) return "DEX_TO_DEX";
        return "TRANSFER";
    }

    function getTaxRateForTransfer(address from, address to) external view returns (uint256 taxRate) {
        (, uint256 rate,) = _getTaxInfo(from, to); return rate;
    }

    function getAllDexPairs() external view returns (address[] memory) { return _dexPairs; }
    function getDexPairCount() external view returns (uint256) { return _dexPairs.length; }
    function getMarketingWallet() external view returns (address) { return taxDistribution.marketingWallet; }
    function getTeamWallet() external view returns (address) { return taxDistribution.teamWallet; }
    function getBuybackWallet() external view returns (address) { return taxDistribution.buybackWallet; }
    function isTaxEnabled() external view returns (bool) { return taxBehavior.taxOnBuy || taxBehavior.taxOnSell || taxBehavior.taxOnTransfer; }

    function getMaxActiveTaxRate() external view returns (uint256) {
        uint256 maxRate = 0;
        if (taxBehavior.taxOnTransfer && taxBehavior.transferTax > maxRate) maxRate = taxBehavior.transferTax;
        if (taxBehavior.taxOnBuy && taxBehavior.buyTax > maxRate) maxRate = taxBehavior.buyTax;
        if (taxBehavior.taxOnSell && taxBehavior.sellTax > maxRate) maxRate = taxBehavior.sellTax;
        return maxRate;
    }

    function buyTax() external view returns (uint256) { return taxBehavior.buyTax; }
    function sellTax() external view returns (uint256) { return taxBehavior.sellTax; }
    function transferTax() external view returns (uint256) { return taxBehavior.transferTax; }

    // Deflationary-specific views
    function totalBurned() external view returns (uint256) { return _totalBurned; }

    function calculateBurn(address from, address to, uint256 amount) external view returns (uint256 burnAmount, uint256 netAmount) {
        (uint256 totalTax, uint256 afterTax,) = this.calculateTax(from, to, amount);
        burnAmount = (totalTax * taxDistribution.deflationPercent) / BASIS_POINTS;
        netAmount = afterTax;
    }

    function isDeflationEnabled() external view returns (bool) {
        return taxDistribution.deflationPercent > 0 &&
            (taxBehavior.taxOnBuy || taxBehavior.taxOnSell || taxBehavior.taxOnTransfer);
    }

    function getCirculatingSupply() external view returns (uint256) {
        return totalSupply() - balanceOf(address(this)) - balanceOf(0x000000000000000000000000000000000000dEaD);
    }

    function getBurnStatistics() external view returns (uint256 totalBurned_, uint256 burnPercentage, uint256 circulatingSupply) {
        totalBurned_ = _totalBurned;
        uint256 original = totalSupply();
        burnPercentage = original > 0 ? (_totalBurned * BASIS_POINTS) / original : 0;
        circulatingSupply = totalSupply() - balanceOf(address(this)) - balanceOf(0x000000000000000000000000000000000000dEaD);
    }

}

contracts/FatFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/proxy/Clones.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./FatStandard.sol";
import "./FatTax.sol";
import "./FatDeflationary.sol";
import "./FatReflection.sol";

interface AggregatorV3Interface {
    function latestRoundData() external view returns (
        uint80 roundId,
        int256 answer,
        uint256 startedAt,
        uint256 updatedAt,
        uint80 answeredInRound
    );
    function decimals() external view returns (uint8);
}

/**
 * @title FatFactory
 * @dev Factory for deploying 4 types of highly configurable ERC-20 tokens using EIP-1167 minimal proxy pattern
 *
 * Token Types:
 * 1. FatStandard    - Clean ERC-20 with no automatic fees
 * 2. FatTax         - Configurable tax on transfers/buys/sells distributed to multiple wallets
 * 3. FatDeflationary - Configurable burn on transfers/buys/sells
 * 4. FatReflection  - Configurable RFI-style reflection on transfers/buys/sells
 *
 * Gas Savings: 80-90% cheaper than deploying full contracts
 * Monetization: Dynamic USD-based deployment fee via Chainlink price feed
 */
contract FatFactory is Ownable, ReentrancyGuard {

    // ============================================
    // STATE VARIABLES
    // ============================================

    enum TokenType { STANDARD, TAX, DEFLATIONARY, REFLECTION }

    struct ImplementationAddresses {
        address standard;
        address tax;
        address deflationary;
        address reflection;
    }

    ImplementationAddresses public implementations;

    address public dexRouter;

    AggregatorV3Interface public priceFeed;
    uint8 public feedDecimals;
    uint256 public feeInUSD;
    uint256 public maxStaleness;

    uint256 public constant MIN_STALENESS = 60;
    uint256 public constant MAX_STALENESS_CAP = 86400;
    uint256 public constant MAX_FEE_USD = 1000e18;

    address public feeReceiver;
    uint256 public totalDeployed;

    mapping(address => address[]) public deployerTokens;
    mapping(address => bool) public isFactoryToken;
    mapping(address => TokenType) public tokenTypes;

    // ============================================
    // EVENTS
    // ============================================

    event TokenCreated(
        address indexed tokenAddress,
        address indexed deployer,
        TokenType indexed tokenType,
        string name,
        string symbol,
        uint256 totalSupply,
        uint256 timestamp
    );

    event FeeInUSDUpdated(uint256 oldFee, uint256 newFee);
    event PriceFeedUpdated(address indexed oldFeed, address indexed newFeed);
    event MaxStalenessUpdated(uint256 oldStaleness, uint256 newStaleness);
    event FeeReceiverUpdated(address indexed oldReceiver, address indexed newReceiver);
    event FeesWithdrawn(address indexed receiver, uint256 amount);
    event ImplementationUpdated(TokenType indexed tokenType, address newImplementation);
    event DexRouterUpdated(address indexed oldRouter, address indexed newRouter);

    // ============================================
    // ERRORS
    // ============================================

    error InsufficientDeploymentFee(uint256 provided, uint256 required);
    error InvalidFeeReceiver();
    error InvalidImplementation();
    error TokenInitializationFailed();
    error NoFeesToWithdraw();
    error FeeTransferFailed();
    error InvalidTokenType();
    error InvalidPriceFeed();
    error StalePrice(uint256 updatedAt, uint256 threshold);
    error IncompleteRound(uint80 roundId, uint80 answeredInRound);
    error InvalidPrice();
    error StalenessOutOfRange(uint256 value, uint256 min, uint256 max);
    error FeeExceedsCap(uint256 fee, uint256 cap);

    // ============================================
    // CONSTRUCTOR
    // ============================================

    constructor(
        address standardImpl_,
        address taxImpl_,
        address deflationaryImpl_,
        address reflectionImpl_,
        address dexRouter_,
        address priceFeed_,
        uint256 feeInUSD_,
        uint256 maxStaleness_,
        address feeReceiver_
    ) Ownable(msg.sender) {
        if (standardImpl_ == address(0) || taxImpl_ == address(0) ||
            deflationaryImpl_ == address(0) || reflectionImpl_ == address(0)) {
            revert InvalidImplementation();
        }
        if (feeReceiver_ == address(0)) revert InvalidFeeReceiver();
        if (dexRouter_ == address(0)) revert InvalidImplementation();
        if (priceFeed_ == address(0)) revert InvalidPriceFeed();
        if (maxStaleness_ < MIN_STALENESS || maxStaleness_ > MAX_STALENESS_CAP) {
            revert StalenessOutOfRange(maxStaleness_, MIN_STALENESS, MAX_STALENESS_CAP);
        }
        if (feeInUSD_ > MAX_FEE_USD) revert FeeExceedsCap(feeInUSD_, MAX_FEE_USD);

        implementations.standard = standardImpl_;
        implementations.tax = taxImpl_;
        implementations.deflationary = deflationaryImpl_;
        implementations.reflection = reflectionImpl_;
        dexRouter = dexRouter_;
        priceFeed = AggregatorV3Interface(priceFeed_);
        feedDecimals = AggregatorV3Interface(priceFeed_).decimals();
        feeInUSD = feeInUSD_;
        maxStaleness = maxStaleness_;
        feeReceiver = feeReceiver_;
    }

    // ============================================
    // CREATE STANDARD TOKEN
    // ============================================

    function createStandardToken(
        string memory name,
        string memory symbol,
        uint8 decimals,
        uint256 totalSupply
    ) external payable nonReentrant returns (address) {
        uint256 requiredFee = getDeploymentFee();
        if (msg.value < requiredFee) {
            revert InsufficientDeploymentFee(msg.value, requiredFee);
        }

        address tokenAddress = Clones.clone(implementations.standard);

        try FatStandard(tokenAddress).initialize(
            name, symbol, decimals, totalSupply, msg.sender
        ) {} catch {
            revert TokenInitializationFailed();
        }

        _recordDeployment(tokenAddress, TokenType.STANDARD, name, symbol, totalSupply);
        _refundExcess(requiredFee);

        return tokenAddress;
    }

    // ============================================
    // CREATE TAX TOKEN
    // ============================================

    function createTaxToken(
        string memory name,
        string memory symbol,
        uint8 decimals,
        uint256 totalSupply,
        FatTax.TaxBehavior memory taxBehavior,
        FatTax.TaxDistribution memory taxDistribution
    ) external payable nonReentrant returns (address) {
        uint256 requiredFee = getDeploymentFee();
        if (msg.value < requiredFee) {
            revert InsufficientDeploymentFee(msg.value, requiredFee);
        }

        address payable tokenAddress = payable(Clones.clone(implementations.tax));

        try FatTax(tokenAddress).initialize(
            name, symbol, decimals, totalSupply, msg.sender, taxBehavior, taxDistribution, dexRouter
        ) {} catch {
            revert TokenInitializationFailed();
        }

        _recordDeployment(tokenAddress, TokenType.TAX, name, symbol, totalSupply);
        _refundExcess(requiredFee);

        return tokenAddress;
    }

    // ============================================
    // CREATE DEFLATIONARY TOKEN
    // ============================================

    function createDeflationaryToken(
        string memory name,
        string memory symbol,
        uint8 decimals,
        uint256 totalSupply,
        FatDeflationary.TaxBehavior memory taxBehavior,
        FatDeflationary.TaxDistribution memory taxDistribution
    ) external payable nonReentrant returns (address) {
        uint256 requiredFee = getDeploymentFee();
        if (msg.value < requiredFee) {
            revert InsufficientDeploymentFee(msg.value, requiredFee);
        }

        address payable tokenAddress = payable(Clones.clone(implementations.deflationary));

        try FatDeflationary(tokenAddress).initialize(
            name, symbol, decimals, totalSupply, msg.sender, taxBehavior, taxDistribution, dexRouter
        ) {} catch {
            revert TokenInitializationFailed();
        }

        _recordDeployment(tokenAddress, TokenType.DEFLATIONARY, name, symbol, totalSupply);
        _refundExcess(requiredFee);

        return tokenAddress;
    }

    // ============================================
    // CREATE REFLECTION TOKEN
    // ============================================

    function createReflectionToken(
        string memory name,
        string memory symbol,
        uint8 decimals,
        uint256 totalSupply,
        FatReflection.TaxBehavior memory taxBehavior,
        FatReflection.TaxDistribution memory taxDistribution
    ) external payable nonReentrant returns (address) {
        uint256 requiredFee = getDeploymentFee();
        if (msg.value < requiredFee) {
            revert InsufficientDeploymentFee(msg.value, requiredFee);
        }

        address payable tokenAddress = payable(Clones.clone(implementations.reflection));

        try FatReflection(tokenAddress).initialize(
            name, symbol, decimals, totalSupply, msg.sender, taxBehavior, taxDistribution, dexRouter
        ) {} catch {
            revert TokenInitializationFailed();
        }

        _recordDeployment(tokenAddress, TokenType.REFLECTION, name, symbol, totalSupply);
        _refundExcess(requiredFee);

        return tokenAddress;
    }

    // ============================================
    // INTERNAL HELPERS
    // ============================================

    function _recordDeployment(
        address tokenAddress,
        TokenType tokenType,
        string memory name,
        string memory symbol,
        uint256 totalSupply
    ) private {
        totalDeployed++;
        deployerTokens[msg.sender].push(tokenAddress);
        isFactoryToken[tokenAddress] = true;
        tokenTypes[tokenAddress] = tokenType;

        emit TokenCreated(
            tokenAddress,
            msg.sender,
            tokenType,
            name,
            symbol,
            totalSupply,
            block.timestamp
        );
    }

    function _refundExcess(uint256 fee) private {
        if (msg.value > fee) {
            (bool success, ) = msg.sender.call{value: msg.value - fee}("");
            if (!success) {} // Intentionally ignore refund failures
        }
    }

    // ============================================
    // VIEW FUNCTIONS
    // ============================================

    function getDeployerTokens(address deployer) external view returns (address[] memory) {
        return deployerTokens[deployer];
    }

    function getDeployerTokenCount(address deployer) external view returns (uint256) {
        return deployerTokens[deployer].length;
    }

    function isFromFactory(address tokenAddress) external view returns (bool) {
        return isFactoryToken[tokenAddress];
    }

    function getTokenType(address tokenAddress) external view returns (TokenType) {
        if (!isFactoryToken[tokenAddress]) revert InvalidTokenType();
        return tokenTypes[tokenAddress];
    }

    function getDeploymentFee() public view returns (uint256) {
        if (feeInUSD == 0) return 0;

        (
            uint80 roundId,
            int256 price,
            ,
            uint256 updatedAt,
            uint80 answeredInRound
        ) = priceFeed.latestRoundData();

        if (price <= 0) revert InvalidPrice();
        if (answeredInRound < roundId) revert IncompleteRound(roundId, answeredInRound);
        if (block.timestamp - updatedAt > maxStaleness) {
            revert StalePrice(updatedAt, maxStaleness);
        }

        return (feeInUSD * (10 ** feedDecimals)) / uint256(price);
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    function getImplementations() external view returns (ImplementationAddresses memory) {
        return implementations;
    }

    // ============================================
    // OWNER FUNCTIONS
    // ============================================

    function setFeeInUSD(uint256 newFee) external onlyOwner {
        if (newFee > MAX_FEE_USD) revert FeeExceedsCap(newFee, MAX_FEE_USD);
        uint256 oldFee = feeInUSD;
        feeInUSD = newFee;
        emit FeeInUSDUpdated(oldFee, newFee);
    }

    function setPriceFeed(address newFeed) external onlyOwner {
        if (newFeed == address(0)) revert InvalidPriceFeed();
        address oldFeed = address(priceFeed);
        priceFeed = AggregatorV3Interface(newFeed);
        feedDecimals = AggregatorV3Interface(newFeed).decimals();
        emit PriceFeedUpdated(oldFeed, newFeed);
    }

    function setMaxStaleness(uint256 newStaleness) external onlyOwner {
        if (newStaleness < MIN_STALENESS || newStaleness > MAX_STALENESS_CAP) {
            revert StalenessOutOfRange(newStaleness, MIN_STALENESS, MAX_STALENESS_CAP);
        }
        uint256 oldStaleness = maxStaleness;
        maxStaleness = newStaleness;
        emit MaxStalenessUpdated(oldStaleness, newStaleness);
    }

    function setFeeReceiver(address newReceiver) external onlyOwner {
        if (newReceiver == address(0)) revert InvalidFeeReceiver();
        address oldReceiver = feeReceiver;
        feeReceiver = newReceiver;
        emit FeeReceiverUpdated(oldReceiver, newReceiver);
    }

    function withdrawFees() external onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        if (balance == 0) revert NoFeesToWithdraw();

        (bool success, ) = feeReceiver.call{value: balance}("");
        if (!success) revert FeeTransferFailed();

        emit FeesWithdrawn(feeReceiver, balance);
    }

    function updateImplementation(TokenType tokenType, address newImplementation) external onlyOwner {
        if (newImplementation == address(0)) revert InvalidImplementation();

        if (tokenType == TokenType.STANDARD) {
            implementations.standard = newImplementation;
        } else if (tokenType == TokenType.TAX) {
            implementations.tax = newImplementation;
        } else if (tokenType == TokenType.DEFLATIONARY) {
            implementations.deflationary = newImplementation;
        } else if (tokenType == TokenType.REFLECTION) {
            implementations.reflection = newImplementation;
        } else {
            revert InvalidTokenType();
        }

        emit ImplementationUpdated(tokenType, newImplementation);
    }

    function setDexRouter(address newRouter) external onlyOwner {
        if (newRouter == address(0)) revert InvalidImplementation();
        address oldRouter = dexRouter;
        dexRouter = newRouter;
        emit DexRouterUpdated(oldRouter, newRouter);
    }

    function recoverERC20(address tokenAddress, uint256 amount) external onlyOwner {
        (bool success, bytes memory data) = tokenAddress.call(
            abi.encodeWithSignature("transfer(address,uint256)", owner(), amount)
        );
        require(success && (data.length == 0 || abi.decode(data, (bool))), "Token recovery failed");
    }

    receive() external payable {}
}

contracts/FatReflection.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Context.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./interfaces/IUniswapV2Router02.sol";

/**
 * @title FatReflection
 * @dev ERC-20 token with UNIFIED fee architecture: single tax rate with reflection as a distribution category
 *
 * Architecture (Unified Fee Model):
 * - ONE single tax rate per transfer type (buy/sell/transfer)
 * - Tax collected is distributed:
 *   - reflectionPercent → redistributed to all holders via RFI mechanism
 *   - marketingPercent  → swapped to ETH → marketing wallet
 *   - liquidityPercent  → auto-added to DEX as liquidity
 *   - teamPercent       → swapped to ETH → team wallet
 *   - buybackPercent    → swapped to ETH → buyback wallet
 *   - All must sum to 10000 (100%)
 *
 * Features:
 * - Separate tax rates for Transfers, Buys, and Sells
 * - Reflection (RFI) is a distribution category, not a separate fee layer
 * - AUTOMATIC reflection to all holders (no claiming needed)
 * - AUTO-SWAP: Non-reflection tax automatically swapped to ETH via DEX Router
 * - AUTO-LIQUIDITY: Liquidity portion auto-added to DEX (LP tokens to owner)
 * - Gas-efficient reflection mechanism (no loops in transfers)
 * - Excludable addresses (liquidity pools, CEX wallets)
 */
contract FatReflection is Context, Ownable, ReentrancyGuard {

    // ============================================
    // STRUCTS
    // ============================================

    struct TaxBehavior {
        bool taxOnTransfer;
        bool taxOnBuy;
        bool taxOnSell;
        uint256 transferTax;
        uint256 buyTax;
        uint256 sellTax;
    }

    struct TaxDistribution {
        uint256 reflectionPercent;  // % redistributed to holders via RFI (0-10000)
        uint256 marketingPercent;
        uint256 liquidityPercent;
        uint256 teamPercent;
        uint256 buybackPercent;
        // These MUST add up to 10000

        address marketingWallet;
        address teamWallet;
        address buybackWallet;
    }

    // ============================================
    // STATE VARIABLES
    // ============================================

    string private _tokenName;
    string private _tokenSymbol;
    uint8 private _decimals;

    TaxBehavior public taxBehavior;
    TaxDistribution public taxDistribution;

    mapping(address => uint256) private _rOwned;
    mapping(address => uint256) private _tOwned;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => bool) private _isExcludedFromFee;
    mapping(address => bool) private _isExcluded;
    mapping(address => bool) public isDexPair;

    address[] private _excluded;
    address[] private _dexPairs;

    IUniswapV2Router02 public dexRouter;
    uint256 public swapTokensAtAmount;
    bool private _inSwap;
    bool public autoSwapEnabled;

    uint256 private constant MAX = ~uint256(0);
    uint256 private _tTotal;
    uint256 private _rTotal;
    uint256 private _tFeeTotal;

    bool private _initialized;

    uint256 public slippageTolerance = 500;
    uint256 public swapDeadline = 300;

    uint256 public constant MAX_TAX = 2500;
    uint256 public constant MAX_SLIPPAGE = 1000;
    uint256 public constant BASIS_POINTS = 10000;
    uint256 public constant MAX_SWAP_MULTIPLIER = 20;
    uint256 public constant MAX_EXCLUDED = 50;

    // ============================================
    // EVENTS
    // ============================================

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event ReflectionDistributed(string transferType, uint256 tFee, uint256 rFee);
    event TaxCollected(address indexed from, string transferType, uint256 totalTax, uint256 tokensToContract);
    event SwapAndDistribute(uint256 tokensSwapped, uint256 ethReceived, uint256 ethToMarketing, uint256 ethToTeam, uint256 ethToBuyback);
    event LiquidityAdded(uint256 tokensAdded, uint256 ethAdded, uint256 liquidity);
    event ExcludedFromReward(address indexed account);
    event IncludedInReward(address indexed account);
    event DexPairUpdated(address indexed pair, bool status);
    event TaxBehaviorUpdated(TaxBehavior newBehavior);
    event TaxDistributionUpdated(TaxDistribution newDistribution);
    event RouterUpdated(address indexed newRouter);
    event SwapThresholdUpdated(uint256 newThreshold);
    event AutoSwapEnabledUpdated(bool enabled);
    event SlippageToleranceUpdated(uint256 newTolerance);
    event SwapDeadlineUpdated(uint256 newDeadline);
    event DistributionFailed(string wallet, uint256 amount);
    event ETHRecovered(uint256 amount);
    event ERC20Recovered(address indexed token, uint256 amount);
    event FeeExclusionChanged(address indexed account, bool excluded);

    // ============================================
    // ERRORS
    // ============================================

    error AlreadyInitialized();
    error TaxTooHigh(uint256 provided, uint256 max);
    error InvalidTaxWallet(string walletType);
    error InvalidDistribution(uint256 total, uint256 expected);
    error InsufficientBalance();
    error InsufficientAllowance();

    // ============================================
    // CONSTRUCTOR
    // ============================================

    constructor() Ownable(msg.sender) {
        // (removed: was clone guard)
    }

    // ============================================
    // INITIALIZATION
    // ============================================

    function initialize(
        string memory name_,
        string memory symbol_,
        uint8 decimals_,
        uint256 totalSupply_,
        address owner_,
        TaxBehavior memory taxBehavior_,
        TaxDistribution memory taxDistribution_,
        address dexRouter_
    ) external {
        if (_initialized) revert AlreadyInitialized();
        require(totalSupply_ > 0, "Total supply must be > 0");

        if (taxBehavior_.transferTax > MAX_TAX) revert TaxTooHigh(taxBehavior_.transferTax, MAX_TAX);
        if (taxBehavior_.buyTax > MAX_TAX) revert TaxTooHigh(taxBehavior_.buyTax, MAX_TAX);
        if (taxBehavior_.sellTax > MAX_TAX) revert TaxTooHigh(taxBehavior_.sellTax, MAX_TAX);

        _validateDistribution(taxDistribution_);

        _tokenName = name_;
        _tokenSymbol = symbol_;
        _decimals = decimals_;
        taxBehavior = taxBehavior_;
        taxDistribution = taxDistribution_;

        dexRouter = IUniswapV2Router02(dexRouter_);
        swapTokensAtAmount = totalSupply_ / 20000;
        autoSwapEnabled = true;

        slippageTolerance = 500;
        swapDeadline = 300;

        _tTotal = totalSupply_;
        _rTotal = (MAX - (MAX % _tTotal));

        _transferOwnership(owner_);

        if (totalSupply_ > 0) {
            _rOwned[owner_] = _rTotal;
            emit Transfer(address(0), owner_, totalSupply_);
        }

        _isExcludedFromFee[owner_] = true;
        _isExcludedFromFee[address(this)] = true;

        if (taxDistribution_.marketingWallet != address(0)) _isExcludedFromFee[taxDistribution_.marketingWallet] = true;
        if (taxDistribution_.teamWallet != address(0)) _isExcludedFromFee[taxDistribution_.teamWallet] = true;
        if (taxDistribution_.buybackWallet != address(0)) _isExcludedFromFee[taxDistribution_.buybackWallet] = true;

        _excludeFromRewardInit(address(this));
        if (taxDistribution_.marketingWallet != address(0)) _excludeFromRewardInit(taxDistribution_.marketingWallet);
        if (taxDistribution_.teamWallet != address(0)) _excludeFromRewardInit(taxDistribution_.teamWallet);
        if (taxDistribution_.buybackWallet != address(0)) _excludeFromRewardInit(taxDistribution_.buybackWallet);

        _initialized = true;
    }

    // ============================================
    // INTERNAL HELPERS
    // ============================================

    function _excludeFromRewardInit(address account) private {
        if (_isExcluded[account]) return;
        if (_rOwned[account] > 0) {
            _tOwned[account] = tokenFromReflection(_rOwned[account]);
        }
        _isExcluded[account] = true;
        _excluded.push(account);
    }

    function _validateDistribution(TaxDistribution memory dist) private pure {
        uint256 totalDistribution = dist.reflectionPercent + dist.marketingPercent +
                                     dist.liquidityPercent + dist.teamPercent + dist.buybackPercent;

        if (totalDistribution != BASIS_POINTS) revert InvalidDistribution(totalDistribution, BASIS_POINTS);
        if (dist.marketingPercent > 0 && dist.marketingWallet == address(0)) revert InvalidTaxWallet("marketing");
        if (dist.teamPercent > 0 && dist.teamWallet == address(0)) revert InvalidTaxWallet("team");
        if (dist.buybackPercent > 0 && dist.buybackWallet == address(0)) revert InvalidTaxWallet("buyback");
    }

    // ============================================
    // ERC20 STANDARD FUNCTIONS
    // ============================================

    function name() public view returns (string memory) { return _tokenName; }
    function symbol() public view returns (string memory) { return _tokenSymbol; }
    function decimals() public view returns (uint8) { return _decimals; }
    function totalSupply() public view returns (uint256) { return _tTotal; }

    function balanceOf(address account) public view returns (uint256) {
        if (_isExcluded[account]) return _tOwned[account];
        return tokenFromReflection(_rOwned[account]);
    }

    function transfer(address to, uint256 amount) public returns (bool) {
        _transfer(_msgSender(), to, amount);
        return true;
    }

    function allowance(address owner, address spender) public view returns (uint256) {
        return _allowances[owner][spender];
    }

    function approve(address spender, uint256 amount) public returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) public returns (bool) {
        uint256 currentAllowance = _allowances[from][_msgSender()];
        if (currentAllowance < amount) revert InsufficientAllowance();
        unchecked { _approve(from, _msgSender(), currentAllowance - amount); }
        _transfer(from, to, amount);
        return true;
    }

    // ============================================
    // REFLECTION MECHANISM
    // ============================================

    function tokenFromReflection(uint256 rAmount) public view returns (uint256) {
        if (rAmount > _rTotal) revert InsufficientBalance();
        return rAmount / _getRate();
    }

    function _getRate() private view returns (uint256) {
        (uint256 rSupply, uint256 tSupply) = _getCurrentSupply();
        return rSupply / tSupply;
    }

    function _getCurrentSupply() private view returns (uint256, uint256) {
        uint256 rSupply = _rTotal;
        uint256 tSupply = _tTotal;

        for (uint256 i = 0; i < _excluded.length; i++) {
            if (_rOwned[_excluded[i]] > rSupply || _tOwned[_excluded[i]] > tSupply) return (_rTotal, _tTotal);
            rSupply -= _rOwned[_excluded[i]];
            tSupply -= _tOwned[_excluded[i]];
        }

        if (rSupply < _rTotal / _tTotal) return (_rTotal, _tTotal);
        return (rSupply, tSupply);
    }

    function _reflectFee(uint256 rFee, uint256 tFee, string memory transferType) private {
        _rTotal -= rFee;
        _tFeeTotal += tFee;
        emit ReflectionDistributed(transferType, tFee, rFee);
    }

    // ============================================
    // TRANSFER LOGIC
    // ============================================

    function _transfer(address from, address to, uint256 amount) private {
        if (from == address(0) || to == address(0)) revert("Transfer from/to zero address");
        if (amount == 0) { emit Transfer(from, to, 0); return; }
        if (balanceOf(from) < amount) revert InsufficientBalance();

        (bool shouldTax, uint256 taxRate, string memory transferType) = _getFeesInfo(from, to);
        _tokenTransfer(from, to, amount, shouldTax, taxRate, transferType);
    }

    function _getFeesInfo(address from, address to)
        private view
        returns (bool shouldTax, uint256 taxRate, string memory transferType)
    {
        if (_isExcludedFromFee[from] || _isExcludedFromFee[to]) return (false, 0, "EXEMPT");

        bool isBuy = isDexPair[from] && !isDexPair[to];
        bool isSell = !isDexPair[from] && isDexPair[to];
        bool isTransfer = !isDexPair[from] && !isDexPair[to];

        if (isBuy) {
            transferType = "BUY"; shouldTax = taxBehavior.taxOnBuy; taxRate = taxBehavior.buyTax;
        } else if (isSell) {
            transferType = "SELL"; shouldTax = taxBehavior.taxOnSell; taxRate = taxBehavior.sellTax;
        } else if (isTransfer) {
            transferType = "TRANSFER"; shouldTax = taxBehavior.taxOnTransfer; taxRate = taxBehavior.transferTax;
        } else {
            transferType = "DEX_TO_DEX"; shouldTax = false; taxRate = 0;
        }
    }

    function _tokenTransfer(
        address sender, address recipient, uint256 tAmount,
        bool shouldTax, uint256 taxRate, string memory transferType
    ) private {
        uint256 currentRate = _getRate();

        uint256 tTotalFee = 0;
        if (shouldTax && taxRate > 0) {
            tTotalFee = (tAmount * taxRate) / BASIS_POINTS;
        }

        uint256 tReflectionFee = 0;
        uint256 tContractFee = 0;
        if (tTotalFee > 0) {
            tReflectionFee = (tTotalFee * taxDistribution.reflectionPercent) / BASIS_POINTS;
            tContractFee = tTotalFee - tReflectionFee;
        }

        uint256 tTransferAmount = tAmount - tTotalFee;

        uint256 rAmount = tAmount * currentRate;
        uint256 rReflectionFee = tReflectionFee * currentRate;
        uint256 rContractFee = tContractFee * currentRate;
        uint256 rTransferAmount = rAmount - rReflectionFee - rContractFee;

        if (_isExcluded[sender]) _tOwned[sender] -= tAmount;
        _rOwned[sender] -= rAmount;

        if (tReflectionFee > 0) {
            _reflectFee(rReflectionFee, tReflectionFee, transferType);
        }

        if (tContractFee > 0) {
            if (_isExcluded[address(this)]) _tOwned[address(this)] += tContractFee;
            _rOwned[address(this)] += rContractFee;
            emit TaxCollected(sender, transferType, tTotalFee, tContractFee);

            if (autoSwapEnabled) {
                uint256 contractBalance = balanceOf(address(this));
                bool canSwap = contractBalance >= swapTokensAtAmount;

                if (canSwap && !_inSwap && !isDexPair[sender]) {
                    uint256 maxSwap = swapTokensAtAmount * MAX_SWAP_MULTIPLIER;
                    uint256 swapAmount = contractBalance > maxSwap ? maxSwap : contractBalance;
                    try this.autoSwapEntry(swapAmount) {} catch {}
                }
            }
        }

        if (_isExcluded[recipient]) _tOwned[recipient] += tTransferAmount;
        _rOwned[recipient] += rTransferAmount;

        emit Transfer(sender, recipient, tTransferAmount);
    }

    function autoSwapEntry(uint256 amount) external {
        require(msg.sender == address(this), "Only self");
        _swapAndDistribute(amount);
    }

    function _approve(address owner, address spender, uint256 amount) private {
        if (owner == address(0) || spender == address(0)) revert("Approve from/to zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }

    // ============================================
    // SWAP & LIQUIDITY FUNCTIONS
    // ============================================

    modifier lockTheSwap {
        _inSwap = true;
        _;
        _inSwap = false;
    }

    function _swapTokensForEth(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = dexRouter.WETH();
        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount, 0, path, address(this), block.timestamp + swapDeadline
        );
    }

    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        address lpRecipient = owner();
        if (lpRecipient == address(0)) lpRecipient = 0x000000000000000000000000000000000000dEaD;
        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.addLiquidityETH{value: ethAmount}(address(this), tokenAmount, 0, 0, lpRecipient, block.timestamp + swapDeadline);
        emit LiquidityAdded(tokenAmount, ethAmount, 0);
    }

    function _swapAndDistribute(uint256 taxAmount) private lockTheSwap {
        uint256 nonReflectionTotal = BASIS_POINTS - taxDistribution.reflectionPercent;
        if (nonReflectionTotal == 0) return;

        uint256 liquidityTokens = (taxAmount * taxDistribution.liquidityPercent) / nonReflectionTotal;
        uint256 swapTokens = taxAmount - liquidityTokens;

        if (liquidityTokens > 0) {
            uint256 half = liquidityTokens / 2;
            uint256 otherHalf = liquidityTokens - half;
            uint256 initialBalance = address(this).balance;
            _swapTokensForEth(half);
            _addLiquidity(otherHalf, address(this).balance - initialBalance);
        }

        if (swapTokens > 0) {
            uint256 initialBalance = address(this).balance;
            _swapTokensForEth(swapTokens);
            uint256 ethForDistribution = address(this).balance - initialBalance;

            uint256 totalDistPercent = taxDistribution.marketingPercent + taxDistribution.teamPercent + taxDistribution.buybackPercent;
            uint256 ethToMarketing = 0; uint256 ethToTeam = 0; uint256 ethToBuyback = 0;

            if (totalDistPercent > 0) {
                ethToMarketing = (ethForDistribution * taxDistribution.marketingPercent) / totalDistPercent;
                ethToTeam = (ethForDistribution * taxDistribution.teamPercent) / totalDistPercent;
                ethToBuyback = ethForDistribution - ethToMarketing - ethToTeam;
            }

            if (ethToMarketing > 0) { (bool s,) = taxDistribution.marketingWallet.call{value: ethToMarketing}(""); if (!s) emit DistributionFailed("marketing", ethToMarketing); }
            if (ethToTeam > 0) { (bool s,) = taxDistribution.teamWallet.call{value: ethToTeam}(""); if (!s) emit DistributionFailed("team", ethToTeam); }
            if (ethToBuyback > 0) { (bool s,) = taxDistribution.buybackWallet.call{value: ethToBuyback}(""); if (!s) emit DistributionFailed("buyback", ethToBuyback); }

            emit SwapAndDistribute(swapTokens, ethForDistribution, ethToMarketing, ethToTeam, ethToBuyback);
        }
    }

    receive() external payable {}

    function recoverETH() external onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        require(balance > 0, "No ETH to recover");
        (bool success,) = owner().call{value: balance}("");
        require(success, "ETH recovery failed");
        emit ETHRecovered(balance);
    }

    function recoverERC20(address tokenAddress, uint256 amount) external onlyOwner {
        require(tokenAddress != address(this), "Cannot recover own tokens");
        require(amount > 0, "Amount must be > 0");
        IERC20(tokenAddress).transfer(owner(), amount);
        emit ERC20Recovered(tokenAddress, amount);
    }

    function manualSwap() external onlyOwner nonReentrant {
        uint256 contractBalance = balanceOf(address(this));
        require(contractBalance > 0, "No tokens to swap");
        _swapAndDistribute(contractBalance);
    }

    function manualSwapAmount(uint256 amount) external onlyOwner nonReentrant {
        uint256 contractBalance = balanceOf(address(this));
        require(amount > 0 && amount <= contractBalance, "Invalid amount");
        _swapAndDistribute(amount);
    }

    // ============================================
    // OWNER FUNCTIONS
    // ============================================

    function excludeFromReward(address account) external onlyOwner {
        if (_isExcluded[account]) return;
        require(_excluded.length < MAX_EXCLUDED, "Too many excluded addresses");
        if (_rOwned[account] > 0) _tOwned[account] = tokenFromReflection(_rOwned[account]);
        _isExcluded[account] = true;
        _excluded.push(account);
        emit ExcludedFromReward(account);
    }

    function includeInReward(address account) external onlyOwner {
        if (!_isExcluded[account]) return;
        for (uint256 i = 0; i < _excluded.length; i++) {
            if (_excluded[i] == account) {
                _tOwned[account] = 0;
                _isExcluded[account] = false;
                _excluded[i] = _excluded[_excluded.length - 1];
                _excluded.pop();
                emit IncludedInReward(account);
                break;
            }
        }
    }

    function excludeFromFee(address account) external onlyOwner { _isExcludedFromFee[account] = true; emit FeeExclusionChanged(account, true); }
    function includeInFee(address account) external onlyOwner { _isExcludedFromFee[account] = false; emit FeeExclusionChanged(account, false); }

    function setDexPair(address pair, bool status) public onlyOwner {
        if (status && !isDexPair[pair]) { _dexPairs.push(pair); }
        else if (!status && isDexPair[pair]) {
            for (uint256 i = 0; i < _dexPairs.length; i++) {
                if (_dexPairs[i] == pair) { _dexPairs[i] = _dexPairs[_dexPairs.length - 1]; _dexPairs.pop(); break; }
            }
        }
        isDexPair[pair] = status;
        emit DexPairUpdated(pair, status);
    }

    function setDexPairBatch(address[] calldata pairs, bool status) external onlyOwner {
        for (uint256 i = 0; i < pairs.length; i++) { setDexPair(pairs[i], status); }
    }

    function updateTaxBehavior(TaxBehavior memory newBehavior) external onlyOwner {
        if (newBehavior.transferTax > MAX_TAX) revert TaxTooHigh(newBehavior.transferTax, MAX_TAX);
        if (newBehavior.buyTax > MAX_TAX) revert TaxTooHigh(newBehavior.buyTax, MAX_TAX);
        if (newBehavior.sellTax > MAX_TAX) revert TaxTooHigh(newBehavior.sellTax, MAX_TAX);
        taxBehavior = newBehavior;
        emit TaxBehaviorUpdated(newBehavior);
    }

    function updateTaxDistribution(TaxDistribution memory newDistribution) external onlyOwner {
        _validateDistribution(newDistribution);

        if (taxDistribution.marketingWallet != address(0)) _isExcludedFromFee[taxDistribution.marketingWallet] = false;
        if (taxDistribution.teamWallet != address(0)) _isExcludedFromFee[taxDistribution.teamWallet] = false;
        if (taxDistribution.buybackWallet != address(0)) _isExcludedFromFee[taxDistribution.buybackWallet] = false;

        taxDistribution = newDistribution;

        if (newDistribution.marketingWallet != address(0)) _isExcludedFromFee[newDistribution.marketingWallet] = true;
        if (newDistribution.teamWallet != address(0)) _isExcludedFromFee[newDistribution.teamWallet] = true;
        if (newDistribution.buybackWallet != address(0)) _isExcludedFromFee[newDistribution.buybackWallet] = true;

        emit TaxDistributionUpdated(newDistribution);
    }

    function setDexRouter(address newRouter) external onlyOwner { require(newRouter != address(0), "Invalid router"); dexRouter = IUniswapV2Router02(newRouter); emit RouterUpdated(newRouter); }
    function setSwapThreshold(uint256 newThreshold) external onlyOwner { require(newThreshold > 0, "Threshold must be > 0"); require(newThreshold <= _tTotal / 50, "Threshold too high"); swapTokensAtAmount = newThreshold; emit SwapThresholdUpdated(newThreshold); }
    function setSlippageTolerance(uint256 newTolerance) external onlyOwner { require(newTolerance <= MAX_SLIPPAGE, "Slippage too high"); slippageTolerance = newTolerance; emit SlippageToleranceUpdated(newTolerance); }
    function setSwapDeadline(uint256 newDeadline) external onlyOwner { require(newDeadline >= 60 && newDeadline <= 3600, "Deadline must be 1-60 minutes"); swapDeadline = newDeadline; emit SwapDeadlineUpdated(newDeadline); }
    function setAutoSwapEnabled(bool enabled) external onlyOwner { autoSwapEnabled = enabled; emit AutoSwapEnabledUpdated(enabled); }

    // ============================================
    // VIEW FUNCTIONS
    // ============================================

    function isInitialized() external view returns (bool) { return _initialized; }
    function getTaxBehavior() external view returns (TaxBehavior memory) { return taxBehavior; }
    function getTaxDistribution() external view returns (TaxDistribution memory) { return taxDistribution; }
    function totalFees() external view returns (uint256) { return _tFeeTotal; }
    function isExcludedFromReward(address account) external view returns (bool) { return _isExcluded[account]; }
    function isExcludedFromFee(address account) external view returns (bool) { return _isExcludedFromFee[account]; }

    function calculateReflection(address from, address to, uint256 amount)
        external view returns (uint256 reflectionFee, uint256 netAmount, string memory transferType)
    {
        if (from == address(0) || to == address(0)) return (0, amount, "MINT_OR_BURN");
        (bool shouldTax, uint256 taxRate, string memory txType) = _getFeesInfo(from, to);
        uint256 totalFee = 0;
        if (shouldTax && taxRate > 0) {
            totalFee = (amount * taxRate) / BASIS_POINTS;
            reflectionFee = (totalFee * taxDistribution.reflectionPercent) / BASIS_POINTS;
        }
        netAmount = amount - totalFee;
        transferType = txType;
    }

    function canTransfer(address from, address /*to*/, uint256 amount) external view returns (bool success, string memory reason) {
        if (balanceOf(from) < amount) return (false, "Insufficient balance");
        return (true, "");
    }

    function detectTransferType(address from, address to) external view returns (string memory transferType) {
        if (from == address(0)) return "MINT";
        if (to == address(0)) return "BURN";
        if (isDexPair[from] && !isDexPair[to]) return "BUY";
        if (!isDexPair[from] && isDexPair[to]) return "SELL";
        if (isDexPair[from] && isDexPair[to]) return "DEX_TO_DEX";
        return "TRANSFER";
    }

    function getTaxRateForTransfer(address from, address to) external view returns (uint256 taxRate) {
        (, uint256 rate,) = _getFeesInfo(from, to); return rate;
    }

    function getAllDexPairs() external view returns (address[] memory) { return _dexPairs; }
    function getDexPairCount() external view returns (uint256) { return _dexPairs.length; }

    function isReflectionEnabled() external view returns (bool) { return taxDistribution.reflectionPercent > 0; }

    function getReflectionStatistics() external view returns (uint256 totalReflected, uint256 reflectionRate) {
        totalReflected = _tFeeTotal;
        reflectionRate = _getRate();
    }

    function buyTax() external view returns (uint256) { return taxBehavior.buyTax; }
    function sellTax() external view returns (uint256) { return taxBehavior.sellTax; }
    function transferTax() external view returns (uint256) { return taxBehavior.transferTax; }

}

